import React, { useState } from 'react';

const Heatmap = ({ data }) => {
  const [hoveredCell, setHoveredCell] = useState(null);
  const countries = Object.keys(data);
  const categories = ['Entertainment', 'Music', 'News & Politics', 'Comedy', 'Sports', 'Gaming'];

  // Generate simulated heatmap data based on actual country data
  const heatmapData = [];
  countries.forEach(country => {
    categories.forEach(category => {
      const baseValue = data[country]?.avgViews || 0;
      const variation = (Math.random() * 0.5 + 0.75); // 75-125% of base
      const value = (baseValue / 10000) * variation + (Math.random() * 20);
      heatmapData.push({
        country,
        category,
        value: Math.min(100, Math.max(0, value))
      });
    });
  });

  const maxValue = Math.max(...heatmapData.map(d => d.value));
  const getColor = (value, isHovered = false) => {
    const intensity = value / maxValue;
    if (isHovered) {
      return `rgba(231, 76, 60, ${Math.max(0.7, intensity)})`;
    }
    return `rgba(52, 152, 219, ${intensity})`;
  };

  const cellSize = 80;

  return (
    <div>
      <h2>Country Activity Heatmap</h2>
      <div className="chart-container">
        <div style={{ 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center',
          padding: '20px',
          overflow: 'auto'
        }}>
          {/* Category labels */}
          <div style={{ display: 'flex', marginBottom: '10px' }}>
            <div style={{ width: `${cellSize}px` }}></div>
            {categories.map(category => (
              <div 
                key={category}
                style={{ 
                  width: `${cellSize}px`, 
                  textAlign: 'center', 
                  fontSize: '11px',
                  fontWeight: 'bold',
                  padding: '5px',
                  transform: 'rotate(-45deg)',
                  transformOrigin: 'center'
                }}
              >
                {category.length > 10 ? category.substring(0, 10) + '...' : category}
              </div>
            ))}
          </div>

          {/* Heatmap grid */}
          {countries.map(country => (
            <div key={country} style={{ display: 'flex' }}>
              <div style={{ 
                width: `${cellSize}px`, 
                height: `${cellSize}px`,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontWeight: 'bold',
                fontSize: '12px'
              }}>
                {country}
              </div>
              {categories.map(category => {
                const cellData = heatmapData.find(d => d.country === country && d.category === category);
                return (
                  <div
                    key={`${country}-${category}`}
                    style={{
                      width: `${cellSize}px`,
                      height: `${cellSize}px`,
                      backgroundColor: getColor(
                        cellData.value, 
                        hoveredCell === `${country}-${category}`
                      ),
                      border: hoveredCell === `${country}-${category}` 
                        ? '2px solid #e74c3c' 
                        : '1px solid white',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: '12px',
                      fontWeight: hoveredCell === `${country}-${category}` ? 'bold' : 'normal',
                      cursor: 'pointer',
                      transition: 'all 0.3s ease',
                      transform: hoveredCell === `${country}-${category}` ? 'scale(1.05)' : 'scale(1)',
                      zIndex: hoveredCell === `${country}-${category}` ? 10 : 1,
                      position: 'relative',
                      color: cellData.value > maxValue * 0.5 ? 'white' : '#333'
                    }}
                    onMouseEnter={() => setHoveredCell(`${country}-${category}`)}
                    onMouseLeave={() => setHoveredCell(null)}
                    title={`${country} - ${category}: ${cellData.value.toFixed(1)} activity score`}
                  >
                    {cellData.value.toFixed(0)}
                    {hoveredCell === `${country}-${category}` && (
                      <div style={{
                        position: 'absolute',
                        top: '-40px',
                        left: '50%',
                        transform: 'translateX(-50%)',
                        backgroundColor: 'rgba(0,0,0,0.9)',
                        color: 'white',
                        padding: '8px 12px',
                        borderRadius: '6px',
                        fontSize: '11px',
                        whiteSpace: 'nowrap',
                        zIndex: 20,
                        boxShadow: '0 4px 12px rgba(0,0,0,0.3)'
                      }}>
                        {country} - {category}<br/>
                        Score: {cellData.value.toFixed(1)}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}

          {/* Legend */}
          <div style={{ marginTop: '20px', display: 'flex', alignItems: 'center' }}>
            <span style={{ marginRight: '10px', fontSize: '12px' }}>Low</span>
            <div style={{ 
              width: '200px', 
              height: '20px', 
              background: 'linear-gradient(to right, rgba(52, 152, 219, 0.1), rgba(52, 152, 219, 1))',
              border: '1px solid #ccc'
            }}></div>
            <span style={{ marginLeft: '10px', fontSize: '12px' }}>High</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Heatmap;
